from flask import Flask, jsonify
import pymemcache

app = Flask(__name__)

# Connect to Memcached at localhost:11211 using the pymemcache library
memcached_client = pymemcache.Client(['localhost:11211'])

# Define a cache key for database query results
db_query_key = 'db_query_results'

# Define a cache key for API responses
api_response_key = 'api_response'

# Set the TTL values for the cache keys
db_query_ttl = 300 # seconds
api_response_ttl = 60 # seconds

@app.route('/')
def index():
    # Get the database query results from Memcached
    db_query_results = memcached_client.get(db_query_key)

    # If the cache key is not found, execute the database query and store the results in Memcached
    if db_query_results is None:
        # Execute the database query and get the results
        db_query_results = [{'id': 1, 'name': 'John Doe'}, {'id': 2, 'name': 'Jane Doe'}]

        # Set the cache key with the TTL value
        memcached_client.set(db_query_key, db_query_results, db_query_ttl)

    return jsonify(db_query_results)

@app.route('/api')
def api():
    # Get the API response from Memcached
    api_response = memcached_client.get(api_response_key)

    # If the cache key is not found, execute the API call and store the results in Memcached
    if api_response is None:
        # Execute the API call and get the response
        api_response = {'status': 'success', 'message': 'API call successful'}

        # Set the cache key with the TTL value
        memcached_client.set(api_response_key, api_response, api_response_ttl)

    return jsonify(api_response)